class Solution { public: int trap(vector<int>& height) { int n = height.size(); int leftMax = height[0]; int rightMax = height[n-1]; int l = 0; int r = n-1; int res = 0; while( l <= r){ if(leftMax > rightMax){ if( height[r] > rightMax){ rightMax = height[r]; } res += rightMax - height[r]; r--; } else { if(height[l] > leftMax){ leftMax = height[l]; } res += leftMax - height[l]; l++; } } return res; } }; 